import { Schema as S } from 'effect'
import type { Attribute, Html } from 'foldkit/html'
import { html } from 'foldkit/html'

import { cn } from '../../../utils/cn'
import * as BasePopover from '../../base-ui/popover'

// MODEL

export type PopoverAlign = BasePopover.PopoverAlign
export type PopoverChangeReason = BasePopover.PopoverChangeReason
export type PopoverModalMode = BasePopover.PopoverModalMode
export type PopoverOpenChange = BasePopover.PopoverOpenChange
export type PopoverSide = BasePopover.PopoverSide
export type PopoverTransitionStatus = BasePopover.PopoverTransitionStatus

export const PopoverStyleOptions = S.Struct({
  className: S.optional(S.String),
  triggerClassName: S.optional(S.String),
  portalClassName: S.optional(S.String),
  positionerClassName: S.optional(S.String),
  contentClassName: S.optional(S.String),
  headerClassName: S.optional(S.String),
  titleClassName: S.optional(S.String),
  descriptionClassName: S.optional(S.String),
  dir: S.optional(S.String),
})
export type PopoverStyleOptions = typeof PopoverStyleOptions.Type

// UPDATE

export const {
  FocusPopover,
  RestorePopoverFocus,
  arrowId,
  closeOpenChange,
  commandForOpenChange,
  descriptionId,
  escapeOpenChange,
  openChange,
  outsideOpenChange,
  popupId,
  positionerId,
  titleId,
  triggerId,
  triggerOpenChange,
  triggerSelector,
} = BasePopover

// VIEW

export type PopoverAttributes<Message> =
  BasePopover.PopoverAttributes<Message> &
    Readonly<{
      header: ReadonlyArray<Attribute<Message>>
    }>
export type PopoverPartAttributes<Message> =
  BasePopover.PopoverPartAttributes<Message>

export type ViewConfig<Message> = Omit<
  BasePopover.ViewConfig<Message>,
  'toView'
> &
  PopoverStyleOptions &
  Readonly<{
    toView?: (attributes: PopoverAttributes<Message>) => Html
  }>

const positionerBaseClassName = 'isolate z-50'

const contentBaseClassName =
  'z-50 flex w-72 origin-(--transform-origin) flex-col gap-2.5 rounded-lg bg-popover p-2.5 text-sm text-popover-foreground shadow-md ring-1 ring-foreground/10 outline-hidden duration-100 data-[side=bottom]:slide-in-from-top-2 data-[side=inline-end]:slide-in-from-left-2 data-[side=inline-start]:slide-in-from-right-2 data-[side=left]:slide-in-from-right-2 data-[side=right]:slide-in-from-left-2 data-[side=top]:slide-in-from-bottom-2 data-open:animate-in data-open:fade-in-0 data-open:zoom-in-95 data-closed:animate-out data-closed:fade-out-0 data-closed:zoom-out-95'

const contentRtlBaseClassName =
  'z-50 flex w-72 origin-(--transform-origin) flex-col gap-2.5 rounded-lg bg-popover p-2.5 text-sm text-popover-foreground shadow-md ring-1 ring-foreground/10 outline-hidden duration-100 data-[side=bottom]:slide-in-from-top-2 data-[side=inline-end]:slide-in-from-start-2 data-[side=inline-start]:slide-in-from-end-2 data-[side=left]:slide-in-from-right-2 data-[side=right]:slide-in-from-left-2 data-[side=top]:slide-in-from-bottom-2 data-open:animate-in data-open:fade-in-0 data-open:zoom-in-95 data-closed:animate-out data-closed:fade-out-0 data-closed:zoom-out-95'

const headerBaseClassName = 'flex flex-col gap-0.5 text-sm'
const titleBaseClassName = 'font-medium'
const descriptionBaseClassName = 'text-muted-foreground'

export const popoverClassName = ({
  className,
}: Pick<PopoverStyleOptions, 'className'> = {}): string => cn(className)

export const popoverPositionerClassName = ({
  className,
}: Readonly<{ className?: string | undefined }> = {}): string =>
  cn(positionerBaseClassName, className)

export const popoverContentClassName = ({
  className,
  dir,
}: Readonly<{
  className?: string | undefined
  dir?: string | undefined
}> = {}): string =>
  cn(dir === 'rtl' ? contentRtlBaseClassName : contentBaseClassName, className)

export const popoverHeaderClassName = ({
  className,
}: Readonly<{ className?: string | undefined }> = {}): string =>
  cn(headerBaseClassName, className)

export const popoverTitleClassName = ({
  className,
}: Readonly<{ className?: string | undefined }> = {}): string =>
  cn(titleBaseClassName, className)

export const popoverDescriptionClassName = ({
  className,
}: Readonly<{ className?: string | undefined }> = {}): string =>
  cn(descriptionBaseClassName, className)

const optionalClassAttribute = <Message>(
  h: ReturnType<typeof html<Message>>,
  className: string,
): ReadonlyArray<Attribute<Message>> =>
  className === '' ? [] : [h.Class(className)]

const slotAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  slot: string,
  className: string,
): ReadonlyArray<Attribute<Message>> => [
  h.DataAttribute('slot', slot),
  ...optionalClassAttribute(h, className),
]

const shadcnAttributes = <Message>(
  h: ReturnType<typeof html<Message>>,
  config: ViewConfig<Message>,
  attributes: BasePopover.PopoverAttributes<Message>,
): PopoverAttributes<Message> => ({
  ...attributes,
  root: [
    ...attributes.root,
    ...slotAttributes(h, 'popover', popoverClassName(config)),
    ...(config.dir === undefined ? [] : [h.Dir(config.dir)]),
  ],
  trigger: [
    ...attributes.trigger,
    ...slotAttributes(h, 'popover-trigger', cn(config.triggerClassName)),
  ],
  portal: [
    ...attributes.portal,
    ...optionalClassAttribute(h, cn(config.portalClassName)),
  ],
  positioner: {
    ...attributes.positioner,
    root:
      attributes.positioner.root.length > 0
        ? [
            ...attributes.positioner.root,
            ...optionalClassAttribute(
              h,
              popoverPositionerClassName({
                className: config.positionerClassName,
              }),
            ),
          ]
        : attributes.positioner.root,
  },
  popup: {
    ...attributes.popup,
    root:
      attributes.popup.root.length > 0
        ? [
            ...attributes.popup.root,
            ...slotAttributes(
              h,
              'popover-content',
              popoverContentClassName({
                className: config.contentClassName,
                dir: config.dir,
              }),
            ),
            ...(config.dir === undefined ? [] : [h.Dir(config.dir)]),
          ]
        : attributes.popup.root,
  },
  title: [
    ...attributes.title,
    ...slotAttributes(
      h,
      'popover-title',
      popoverTitleClassName({ className: config.titleClassName }),
    ),
  ],
  description: [
    ...attributes.description,
    ...slotAttributes(
      h,
      'popover-description',
      popoverDescriptionClassName({
        className: config.descriptionClassName,
      }),
    ),
  ],
  header: slotAttributes(
    h,
    'popover-header',
    popoverHeaderClassName({ className: config.headerClassName }),
  ),
})

export const view = <Message>(config: ViewConfig<Message>): Html => {
  const h = html<Message>()
  const { toView, ...baseConfig } = config

  return BasePopover.view<Message>({
    ...baseConfig,
    toView: attributes => {
      const popoverAttributes = shadcnAttributes(h, config, attributes)

      if (toView !== undefined) {
        return toView(popoverAttributes)
      }

      return h.div(
        [...popoverAttributes.root],
        [
          h.button([...popoverAttributes.trigger], ['Open Popover']),
          h.div(
            [...popoverAttributes.portal],
            popoverAttributes.popup.isMounted
              ? [
                  h.div([...popoverAttributes.backdrop.root], []),
                  h.div(
                    [...popoverAttributes.positioner.root],
                    [
                      h.div(
                        [...popoverAttributes.popup.root],
                        [
                          h.div(
                            [...popoverAttributes.header],
                            [
                              h.h3(
                                [...popoverAttributes.title],
                                ['Dimensions'],
                              ),
                              h.p(
                                [...popoverAttributes.description],
                                ['Set the dimensions for the layer.'],
                              ),
                            ],
                          ),
                        ],
                      ),
                    ],
                  ),
                ]
              : [],
          ),
        ],
      )
    },
  })
}

import type { Html } from 'foldkit/html'
import { html } from 'foldkit/html'

import { view as Popover } from './index'
import type { PopoverAlign, PopoverOpenChange, PopoverSide } from './index'

export type PopoverExampleController<Message> = Readonly<{
  openFor?: (popoverId: string, defaultOpen: boolean) => boolean
  onOpenChange?: (popoverId: string, change: PopoverOpenChange) => Message
}>

const isOpenFor = <Message>(
  controller: PopoverExampleController<Message>,
  popoverId: string,
  defaultOpen: boolean,
): boolean => controller.openFor?.(popoverId, defaultOpen) ?? defaultOpen

const buttonClassName = (className: string): string =>
  [
    'group/button inline-flex shrink-0 items-center justify-center rounded-lg border border-transparent bg-clip-padding text-sm font-medium whitespace-nowrap transition-all outline-none select-none focus-visible:border-ring focus-visible:ring-3 focus-visible:ring-ring/50 active:not-aria-[haspopup]:translate-y-px disabled:pointer-events-none disabled:opacity-50 aria-invalid:border-destructive aria-invalid:ring-3 aria-invalid:ring-destructive/20 dark:aria-invalid:border-destructive/50 dark:aria-invalid:ring-destructive/40 [&_svg]:pointer-events-none [&_svg]:shrink-0 [&_svg:not([class*="size-"])]:size-4',
    className,
  ].join(' ')

const inputClassName =
  'h-8 w-full min-w-0 rounded-lg border border-input bg-transparent px-2.5 py-1 text-base transition-colors outline-none file:inline-flex file:h-6 file:border-0 file:bg-transparent file:text-sm file:font-medium file:text-foreground placeholder:text-muted-foreground focus-visible:border-ring focus-visible:ring-3 focus-visible:ring-ring/50 disabled:pointer-events-none disabled:cursor-not-allowed disabled:bg-input/50 disabled:opacity-50 aria-invalid:border-destructive aria-invalid:ring-3 aria-invalid:ring-destructive/20 md:text-sm dark:bg-input/30 dark:disabled:bg-input/80 dark:aria-invalid:border-destructive/50 dark:aria-invalid:ring-destructive/40'

const popoverShell = <Message>(
  config: Readonly<{
    id: string
    trigger: string
    title: string
    description: string
    side?: PopoverSide
    align?: PopoverAlign
    contentClassName?: string
    dir?: string
    body?: ReadonlyArray<Html>
  }>,
  controller: PopoverExampleController<Message>,
): Html => {
  const h = html<Message>()
  const { onOpenChange } = controller

  return Popover<Message>({
    id: config.id,
    open: isOpenFor(controller, config.id, true),
    ...(onOpenChange === undefined
      ? {}
      : { onOpenChange: change => onOpenChange(config.id, change) }),
    side: config.side,
    align: config.align,
    dir: config.dir,
    contentClassName: config.contentClassName,
    titleId: `${config.id}-title`,
    descriptionId: `${config.id}-description`,
    toView: attributes =>
      h.div(
        [...attributes.root],
        [
          h.button(
            [
              ...attributes.trigger,
              h.Class(
                buttonClassName('border-border bg-background px-2.5 h-8'),
              ),
            ],
            [config.trigger],
          ),
          h.div(
            [...attributes.portal],
            [
              h.div([...attributes.backdrop.root], []),
              h.div(
                [...attributes.positioner.root],
                [
                  h.div(
                    [...attributes.popup.root],
                    [
                      h.div(
                        [...attributes.header],
                        [
                          h.h4([...attributes.title], [config.title]),
                          h.p(
                            [...attributes.description],
                            [config.description],
                          ),
                        ],
                      ),
                      ...(config.body ?? []),
                    ],
                  ),
                ],
              ),
            ],
          ),
        ],
      ),
  })
}

const dimensionFields = (): ReadonlyArray<Html> => {
  const h = html<never>()
  const fields: ReadonlyArray<
    Readonly<{ id: string; label: string; value: string }>
  > = [
    { id: 'width', label: 'Width', value: '100%' },
    { id: 'maxWidth', label: 'Max. width', value: '300px' },
    { id: 'height', label: 'Height', value: '25px' },
    { id: 'maxHeight', label: 'Max. height', value: 'none' },
  ]

  return [
    h.div(
      [h.Class('grid gap-2')],
      fields.map(field =>
        h.div(
          [h.Class('grid grid-cols-3 items-center gap-4')],
          [
            h.label([h.Attribute('for', field.id)], [field.label]),
            h.input([
              h.Id(field.id),
              h.Value(field.value),
              h.Class(`${inputClassName} col-span-2 h-8`),
            ]),
          ],
        ),
      ),
    ),
  ]
}

const compactFields = (): ReadonlyArray<Html> => {
  const h = html<never>()

  return [
    h.div(
      [h.Class('grid gap-4')],
      [
        h.div(
          [h.Class('grid grid-cols-2 items-center gap-4')],
          [
            h.label([h.Attribute('for', 'width')], ['Width']),
            h.input([h.Id('width'), h.Value('100%'), h.Class(inputClassName)]),
          ],
        ),
        h.div(
          [h.Class('grid grid-cols-2 items-center gap-4')],
          [
            h.label([h.Attribute('for', 'height')], ['Height']),
            h.input([h.Id('height'), h.Value('25px'), h.Class(inputClassName)]),
          ],
        ),
      ],
    ),
  ]
}

export const PopoverBasic = <Message = never>(
  controller: PopoverExampleController<Message> = {},
): Html =>
  popoverShell(
    {
      id: 'popover-basic',
      trigger: 'Open Popover',
      title: 'Dimensions',
      description: 'Set the dimensions for the layer.',
      align: 'start',
    },
    controller,
  )

export const PopoverDemo = <Message = never>(
  controller: PopoverExampleController<Message> = {},
): Html => {
  const h = html<never>()

  return popoverShell(
    {
      id: 'popover-demo',
      trigger: 'Open popover',
      title: 'Dimensions',
      description: 'Set the dimensions for the layer.',
      align: 'start',
      contentClassName: 'w-80',
      body: [
        h.div(
          [h.Class('grid gap-4')],
          [h.div([h.Class('space-y-2')], []), ...dimensionFields()],
        ),
      ],
    },
    controller,
  )
}

export const PopoverForm = <Message = never>(
  controller: PopoverExampleController<Message> = {},
): Html =>
  popoverShell(
    {
      id: 'popover-form',
      trigger: 'Open Popover',
      title: 'Dimensions',
      description: 'Set the dimensions for the layer.',
      align: 'start',
      contentClassName: 'w-64',
      body: compactFields(),
    },
    controller,
  )

const alignmentPopover = <Message>(
  align: PopoverAlign,
  trigger: string,
  controller: PopoverExampleController<Message>,
): Html =>
  popoverShell(
    {
      id: `popover-align-${align}`,
      trigger,
      title: `Aligned to ${align}`,
      description: `Aligned to ${align}`,
      align,
      contentClassName: 'w-40',
    },
    controller,
  )

export const PopoverAlignments = <Message = never>(
  controller: PopoverExampleController<Message> = {},
): Html => {
  const h = html<never>()

  return h.div(
    [h.Class('flex gap-6')],
    [
      alignmentPopover('start', 'Start', controller),
      alignmentPopover('center', 'Center', controller),
      alignmentPopover('end', 'End', controller),
    ],
  )
}

const rtlPopover = <Message>(
  side: PopoverSide,
  trigger: string,
  title: string,
  description: string,
  controller: PopoverExampleController<Message>,
): Html =>
  popoverShell(
    {
      id: `popover-rtl-${side}`,
      trigger,
      title,
      description,
      side,
      dir: 'rtl',
    },
    controller,
  )

export const PopoverRtl = <Message = never>(
  controller: PopoverExampleController<Message> = {},
): Html => {
  const h = html<never>()

  return h.div(
    [h.Class('grid gap-4')],
    [
      h.div(
        [h.Class('flex flex-wrap justify-center gap-2')],
        [
          rtlPopover(
            'left',
            'Left',
            'Dimensions',
            'Set the dimensions.',
            controller,
          ),
          rtlPopover(
            'top',
            'Top',
            'Dimensions',
            'Set the dimensions.',
            controller,
          ),
          rtlPopover(
            'bottom',
            'Bottom',
            'Dimensions',
            'Set the dimensions.',
            controller,
          ),
          rtlPopover(
            'right',
            'Right',
            'Dimensions',
            'Set the dimensions.',
            controller,
          ),
        ],
      ),
      h.div(
        [h.Class('flex flex-wrap justify-center gap-2')],
        [
          rtlPopover(
            'inline-start',
            'Inline Start',
            'Dimensions',
            'Set the dimensions.',
            controller,
          ),
          rtlPopover(
            'inline-end',
            'Inline End',
            'Dimensions',
            'Set the dimensions.',
            controller,
          ),
        ],
      ),
    ],
  )
}

